    {v:"Fleet",ic:"▲",c:AM,id:"fleet",before:"Audits catch violations monthly. GPS tracks location, not behaviour. 12M+ trucks, almost none can see.",after:"Compliance is continuous",metric:"60%",ml:"fewer incidents",detail:"Driver fatigue intervention. PPE verified continuously. Predictive maintenance on equipment."}
