    <Sc bg={B2} bt><Rv><Tg c={AM}>Fleet intelligence</Tg><h2 style={{...hd,fontSize:34,fontWeight:700,marginBottom:10}}>One device learns. Every device improves.</h2><p style={{fontSize:17,color:MT,marginBottom:34}}>Encrypted OTA. Federated learning. No raw data shared. Your 500th device is smarter than your 1st.</p></Rv><Rv d={.12}><Fleet /></Rv></Sc>
